const fs = require('fs');
const path = 'input.txt' // The relative location of the input file


function parseText (inputPath) {
  return new Promise((resolve, reject) => {
    const text = fs.readFileSync(inputPath).toString()
    
    let line = 1;
  
    while (text != '') {
      let token = null;
  
      if (/^[A-Z][A-Za-z]*/.test(text)) {
        const [word] = text.match(/^[A-Z][A-Za-z]*(?=( |$)|([.,;?!"':]))/);
  
        switch (word) {
          case 'Start':
            token = {
              type: 'Start',
              line,
            }
  
            break;

          case 'Stop':
            token = {
              type: 'Stop',
              line,
            }
  
            break;

          case 'Input':
            const num = Number(text.match(/[\d]+(?=( |$)|([.,;?!"':]))/)[0])
  
            if (!Number.isInteger(num) || text !== num) {
              reject({
                error: `invalid num: ${line}`,
              })
            }
  
            token = {
              type: 'Input',
              num,
              line,
            }

            break;
          
          case 'Output': 
            const word2 = /[A-Z][a-z]+(?=( |$)|([.,;?!"':]))/.exec(text)[0];
            
            if (word !== word2) {
              reject({
                error: `invalid num: ${line}`,
              })
            }
  
            token = {
              type: 'Output',
              line,
            }

            break;

          default: 
            reject({
              error: `${line}th: Unknown word: '${word}'`,
            })
        }
      } else if (/^[0-9][0-9]*$/.test(text)) {
          const num = text.match(/^[0-9]+(?=( |$)|([.,;?!"':]))/)[0];
          
          if (!Number.isInteger(num) || text !== num) {
            reject({
              error: `invalid num: ${line}`,
            }) 
          }

          token = { 
            type: 'Output',
            num,
            line
          };
      } else {
        return resolve([token]); 
      }
  

      const endOfText = /[^.?!"']*\.?[?!]?"?\s*(.*)/g.exec(text)[1];
      if (!endOfText) {
        reject({ 
          error: `Expected 'End' at ${line}`, 
        }); 
      };
    
      text = endOfText;
  
      resolve([token, text]);
      
      line += 1
    }
  })
}

